using namespace std;

struct UnionFind {
    int N;
    vector<int> par, siz;
    int find(int x) { return (par[x] == x ? x : par[x] = find(par[x])); }
    void merge(int x, int y) {
        x = find(x), y = find(y);
        if (x == y) return;
        if (siz[x] > siz[y]) swap(x, y);
        par[x] = y;
        siz[y] += siz[x];
    }
    UnionFind(int N) : N(N), siz(N, 1), par(N) {
        iota(par.begin(), par.end(), 0);
    }
};

// 方向を表す
int dx[] = {-1, 0, 1, 0}, dy[] = {0, 1, 0, -1};

// 操作
struct Act {
    int type, x, y;
};

struct Game {
    vector<vector<bool>> C;
    vector<vector<bool>> wall_hrz, wall_vert;
    vector<int> X, Y, wall_used, score;
    bool is_finished = false;

    int MAX_WALL = 10;
    int turn = 0;
    vector<Act> acts;

    // 連結性が保たれているかの判定
    bool isConnected() {
        UnionFind uf(81);
        rep(i, 9) rep(j, 9) {
            if (i < 8 && !wall_hrz[i][j]) uf.merge(i * 9 + j, (i + 1) * 9 + j);
            if (j < 8 && !wall_vert[i][j]) uf.merge(i * 9 + j, i * 9 + j + 1);
        }
        return uf.siz[uf.find(0)] == 81;
    }

    // 操作が適正であるかの判定
    bool isOK(Act act) {
        if (act.type == 0) {
            if (act.x == 0)  // 上
                return X[turn] && !wall_hrz[X[turn] - 1][Y[turn]];
            else if (act.x == 1)  // 右
                return Y[turn] != 8 && !wall_vert[X[turn]][Y[turn]];
            else if (act.x == 2)  // 下
                return X[turn] != 8 && !wall_hrz[X[turn]][Y[turn]];
            else if (act.x == 3)  // 左
                return Y[turn] && !wall_vert[X[turn]][Y[turn] - 1];
            else
                return false;
        } else if (act.type == 1) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL) return false; // 11 回目に置こうとしたらアウト
            if (wall_hrz[act.x][act.y] || wall_hrz[act.x][act.y + 1]) // 既に置かれていたらアウト
                return false;
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            bool res = isConnected(); // 連結性チェック
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
            return res;
        } else if (act.type == 2) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL) return false;
            if (wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y])
                return false;
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            bool res = isConnected();
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
            return res;
        } else
            return false;
    }

    // 操作の候補
    vector<Act> candidateActs() {
        vector<Act> res;
        rep(i, 4) {
            if (isOK(Act{0, i, 0}))
                res.push_back(Act{0, i, 0});  // 隣接マスへ移動
        }
        rep(i, 9) rep(j, 9) {
            if (isOK(Act{1, i, j}))
                res.push_back(Act{1, i, j});  // 水平方向の壁
            if (isOK(Act{2, i, j}))
                res.push_back(Act{2, i, j});  // 垂直方向の壁
        }
        return res;
    }

    // 操作を実行する
    bool applyAct(Act act, bool check = true) {
        if (check && !isOK(act)) return false;
        if (act.type == 0) {  // 隣接マスへ移動
            X[turn] += dx[act.x];
            Y[turn] += dy[act.x];
            if (C[X[turn]][Y[turn]]) {
                score[turn]++;
                C[X[turn]][Y[turn]] = false;
            }
        } else if (act.type == 1) {  // 水平方向の壁
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            wall_used[turn]++;
        } else {  // 垂直方向の壁
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            wall_used[turn]++;
        }
        // ゲームが終了しているかの判定
        bool flag = false;
        rep(i, 9) rep(j, 9) {
            if (C[i][j]) flag = true;
        }
        if (!flag) is_finished = true;
        acts.push_back(act);

        // 交代
        turn ^= 1;
        return true;
    }

    // スコアや盤面を出力する（デバッグ用）
    void printBoard() {
        cout << "Score: " << score[0] << " " << score[1] << "\n"
             << "Wall counter: " << wall_used[0] << " " << wall_used[1] << endl
             << endl;
        rep(i, 9) {
            rep(j, 9) {
                if (i == X[0] && j == Y[0] && i == X[1] && j == Y[1])
                    cout << " AB";
                else if (i == X[0] && j == Y[0])
                    cout << " A ";
                else if (i == X[1] && j == Y[1])
                    cout << " B ";
                else {
                    if (C[i][j])
                        cout << " # ";
                    else
                        cout << " . ";
                }
                if (j < 8) cout << (wall_vert[i][j] ? " | " : "   ");
            }
            cout << endl;
            if (i != 8) {
                rep(j, 9) {
                    if (j) cout << "   ";
                    cout << (wall_hrz[i][j] ? "---" : "   ");
                }
            }
            cout << endl;
        }
        cout << endl;
    }
    Game()
        : C(9, vector<bool>(9)),
          wall_hrz(9, vector<bool>(9)),
          wall_vert(9, vector<bool>(9)),
          X(2),
          Y(2),
          wall_used(2),
          score(2) {
        wall_used[0] = wall_used[1] = 0;
        score[0] = score[1] = 0;
        X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
    }
};
int min_dist_to_apple(Game&game,int x,int y){
    queue<pair<int,int>>q;
    q.emplace(x,y);
    vector<vector<int>>dist(9,vector<int>(9,1e9));
    dist[x][y]=0;
    while(!q.empty()){
        auto [now_x,now_y]=q.front();q.pop();
        if(now_x&&!game.wall_hrz[now_x-1][now_y]){
            if(dist[now_x-1][now_y]>dist[now_x][now_y]+1){
                dist[now_x-1][now_y]=dist[now_x][now_y]+1;
                q.emplace(now_x-1,now_y);
            }
        }
        if(now_y!=8&&!game.wall_vert[now_x][now_y]){
            if(dist[now_x][now_y+1]>dist[now_x][now_y]+1){
                dist[now_x][now_y+1]=dist[now_x][now_y]+1;
                q.emplace(now_x,now_y+1);
            }
        }
        if(now_x!=8&&!game.wall_hrz[now_x][now_y]){
            if(dist[now_x+1][now_y]>dist[now_x][now_y]+1){
                dist[now_x+1][now_y]=dist[now_x][now_y]+1;
                q.emplace(now_x+1,now_y);
            }
        }
        if(now_y&&!game.wall_vert[now_x][now_y-1]){
            if(dist[now_x][now_y-1]>dist[now_x][now_y]+1){
                dist[now_x][now_y-1]=dist[now_x][now_y]+1;
                q.emplace(now_x,now_y-1);
            }
        }
    }
    int ret=0;
    int mi=1e9;
    for(int i=0;i<9;i++)for(int j=0;j<9;j++)if(game.C[i][j])ret+=dist[i][j],chmin(mi,dist[i][j]);
    return ret+mi*20;
}
int eval(Game &game){
    return game.score[game.turn^1]*1250+min_dist_to_apple(game,game.X[game.turn],game.Y[game.turn])-min_dist_to_apple(game,game.X[game.turn^1],game.Y[game.turn^1])*2;
}
int cnt=0;
int minmax(Game&game,int depth,bool a){
    if(depth==0){
        return eval(game);
    }
    auto acts=game.candidateActs();
    if(acts.size()==0){
        return eval(game);
    }
    if(a){
        int mx=-1e9;
        for(auto act:acts){
            Game ngame=game;
            ngame.applyAct(act);
            mx=max(mx,minmax(ngame,depth-1,!a));
        }
        return mx;
    }
    else{
        int mi=1e9;
        for(auto act:acts){
            Game ngame=game;
            ngame.applyAct(act);
            mi=min(mi,minmax(ngame,depth-1,!a));
        }
        return mi;
    }
}
