Act choose(Game&game) {
    vector<Act> acts = game.candidateActs();
    int mx = -1e9;
    Act best_act;
    for (Act act : acts) {
        Game new_game = game;
        new_game.applyAct(act);
        if (chmax(mx, eval(new_game))) best_act = act;
    }
    cerr<<mx<<endl;
    return best_act;
}
